SELECT run_id, dataset_id, algorithm_id
FROM benchmark_runs
WHERE status = 'completed';

SELECT version_id, changelog
FROM algorithm_versions
WHERE version IS NOT NULL;

SELECT 
    (SELECT COUNT(run_id) FROM benchmark_runs WHERE status = 'completed') - 
    (SELECT COUNT(DISTINCT user_id) FROM access_logs) AS difference;

SELECT name 
FROM datasets
WHERE complexity = (SELECT MAX(complexity) FROM datasets);

SELECT COUNT(*)
FROM algorithm_versions
WHERE CAST(version AS REAL) < 1.0;

SELECT DISTINCT name
FROM datasets
WHERE name = 'imagenet';

SELECT algorithm_id, update_index_res
FROM benchmark_runs
ORDER BY update_index_res DESC;

SELECT dataset_id, MAX(add_points_res) AS highest_add_points_result
FROM benchmark_runs
GROUP BY dataset_id;
